const e='{% block sw_collapse_panel_header_slot %} <div class="sw-media-collapse__header"> {% block sw_media_collapse_title %} <h4 class="sw-media-collapse__title"> {{ title }} </h4> {% endblock %} {% block sw_media_collapse_buttons %} <div class="sw-media-collapse__indicator"> <mt-icon name="regular-chevron-right-xs" class="sw-media-collapse__button" :class="expandButtonClass" size="10px" /> <mt-icon name="regular-chevron-down-xs" class="sw-media-collapse__button" :class="collapseButtonClass" size="10px" /> </div> {% endblock %} </div> {% endblock %}',s={template:e,props:{title:{type:String,required:!0}},computed:{expandButtonClass(){return{"is--hidden":this.expanded}},collapseButtonClass(){return{"is--hidden":!this.expanded}}}};export{s as default};
